// Generate src/backend/wasm/../decode-ref.js: a tiny bare VP9-lossless keyframe plus its
// expected decoded Y plane. src/backend/probe.js decodes this via the browser's WebCodecs
// VideoDecoder and compares — a mismatch means the engine color-converts VP9 (Firefox), so
// native decode can't be trusted and we fall back to WASM. Regenerated by build-wasm.sh.
import { writeFileSync } from 'node:fs';
import { fileURLToPath } from 'node:url';
import { dirname, join } from 'node:path';
import { createTrackEncoder } from '../../src/backend/wasm/encode.js';

const W=32, H=32;
const plane=new Uint8Array(W*H);
for(let r=0;r<H;r++) for(let c=0;c<W;c++) plane[r*W+c]=(c*16 + r*5) & 0xff;   // matches probe.js

const enc=createTrackEncoder({ kind:'luma', lossless:true, W, H, fps:30 });
const chunk=await enc.push(plane);   // single lossless keyframe
await enc.close();

const b64=(u8)=>Buffer.from(u8).toString('base64');
const out=`// AUTO-GENERATED by native/wasm/gen-decode-ref.mjs — do not edit.
// A tiny VP9-lossless keyframe + its expected Y plane, used by probe.js to verify that native
// WebCodecs decode is bit-exact (and not silently color-converting) on this engine.
export const DECODE_REF = {
  W: ${W}, H: ${H},
  chunkB64: ${JSON.stringify(b64(chunk.data))},
  planeB64: ${JSON.stringify(b64(plane))},
};
`;

const dir=dirname(fileURLToPath(import.meta.url));
const dest=join(dir, '../../src/backend/decode-ref.js');
writeFileSync(dest, out);
console.log(`wrote ${dest} (chunk ${chunk.data.length} bytes)`);
